  sqlgen::sqlite::connect(db_path)
      .and_then(sqlgen::write(records))
      .value();
}

template<typename T>
void modify_eas_records_by_id(const std::string& table_name,
                              int record_id,
                              const std::string& col_name,
                              const T& new_value) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        std::string pk_column;
        if (table_name == "Student") pk_column = "SNo";
        else if (table_name == "Course") pk_column = "CID";
        else if (table_name == "Score") pk_column = "ScID";
        else if (table_name == "Major") pk_column = "MID";

        std::string query = "UPDATE " + table_name + " SET " + col_name + 
                          " = ? WHERE " + pk_column + " = ?";
        return sqlgen::exec(conn, query, new_value, record_id);
      })
      .value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  if (table_name == "Student") {
    sqlgen::sqlite::connect(db_path)
        .and_then(sqlgen::remove<Student> | where("SNo"_c == record_id))
        .value();
  } else if (table_name == "Course") {
    auto id = static_cast<uint32_t>(std::stoul(record_id));
    sqlgen::sqlite::connect(db_path)
        .and_then(sqlgen::remove<Course> | where("CID"_c == id))
        .value();
  } else if (table_name == "Score") {
    auto id = static_cast<uint32_t>(std::stoul(record_id));
    sqlgen::sqlite::connect(db_path)
        .and_then(sqlgen::remove<Score> | where("ScID"_c == id))
        .value();
  } else if (table_name == "Major") {
    auto id = static_cast<uint32_t>(std::stoul(record_id));
    sqlgen::sqlite::connect(db_path)
        .and_then(sqlgen::remove<Major> | where("MID"_c == id))
        .value();
  }
}
