namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto db = sqlite::connection("test_db.sqlite");

  // Begin transaction to ensure safety
  db.begin();

  // Delete users who have not logged in since 2025-01-01
  // (last_login < '2025-01-01')
  db.execute(remove<User> | where("last_login"_c < DateTime("2025-01-01")));

  // Commit the transaction and return the result
  return db.commit();
}

} // namespace delete_inactive_users
