std::vector<EmployeeManager> query_employee_hierarchy() {
    using namespace sqlgen;

    // Connect to SQLite database
    auto db = sqlite::open("test_db.sqlite");

    // Execute self-join query
    // e1 is the employee table, e2 is the manager table (same Employee table)
    // LEFT JOIN ensures employees without managers are included
    auto results = db.query<std::vector<EmployeeManager>>(
        "SELECT e1.name as employee, e2.name as manager "
        "FROM Employee e1 "
        "LEFT JOIN Employee e2 ON e1.manager_id = e2.emp_id"
    );

    return results;
}

}  // namespace query_employee_hierarchy
```

