      })
      .and_then([](auto&& conn) {
        // Drop the original Student table
        return sqlgen::exec(conn, "DROP TABLE Student;");
      })
      .and_then([](auto&& conn) {
        // Recreate Student table with Age column as INTEGER NULL
        return sqlgen::exec(conn, 
          "CREATE TABLE Student ("
          "SNo VARCHAR(10) PRIMARY KEY, "
          "SName VARCHAR(30), "
          "Sex INTEGER DEFAULT 1, "
          "Birthday DATETIME, "
          "Major INTEGER, "
