  ASSERT_TRUE(upsert_user_profile(u2));
  auto rows2 = sqlgen::read<std::vector<UserProfile>>(conn).value();
  ASSERT_EQ(rows2.size(), 1u);
  EXPECT_EQ(rows2[0].bio.value(), "second");
