```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Since SQLite doesn't support RIGHT JOIN natively, we simulate it using LEFT JOIN
  // To include all departments (right side in conceptual RIGHT JOIN), 
  // we put Department on the left in a LEFT JOIN
  // This gives us all departments, even those without projects

  auto result = sqlite::connect("test_db.sqlite")
    .and_then([](auto& conn) -> rfl::Result<std::vector<DepProj>> {
      // Execute raw SQL query to perform the join
      // Department LEFT JOIN Project to get all departments
      const std::string query = 
        R"(SELECT d.name as department_name, p.name as project_name 
           FROM Department d 
           LEFT JOIN Project p ON d.department_id = p.department_id)";

      return conn.template execute<std::vector<DepProj>>(query);
    });

  return result.value_or(std::vector<DepProj>{});
}

}  // namespace right_join_departments_projects
```

**Note:** Since SQLite doesn't natively support RIGHT JOIN, this implementation uses a LEFT JOIN with the tables ordered to achieve the same effect. The `Department LEFT JOIN Project` ensures all departments are included in the results, even those without associated projects (simulating a RIGHT JOIN that would have Project on the left and Department on the right).

