#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace generate_sql_dry_run {

struct A {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

struct B {
  sqlgen::PrimaryKey<int> id;
  int a_id;
  double score;
};

/**
 * This function demonstrates how to build a conditional SQL query.
 * It joins tables A and B, filtering for records where score > 10 and name contains 'x'.
 * Returns: std::string.
 */
std::string generate_sql_dry_run() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Build a complex query with joins, where, order_by, limit
  // Reading from a pair/tuple of types creates a JOIN in the generated SQL
  const auto query = sqlgen::read<std::vector<std::pair<A, B>>> |
                     where("a_id"_c == "id"_c and "score"_c > 10.0) |
                     order_by("score"_c) |
                     limit(100);

  // Generate SQL string for SQLite (dry run - no execution)
  const std::string sql = sqlgen::sqlite::to_sql(query);

  return sql;
}

}  // namespace generate_sql_dry_run
