#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;

  // 1. Connect to SQLite database
  auto conn = sqlgen::sqlite::Connection("test_db.sqlite");

  // 2. Create tables for User and Friendship
  conn.execute(CreateTable<User>{});
  conn.execute(CreateTable<Friendship>{});

  // 3. Insert sample data
  if (!users.empty()) {
    conn.execute(Insert(users));
  }
  if (!friendships.empty()) {
    conn.execute(Insert(friendships));
  }

  // 4. Query for mutual friends using SELF-JOIN
  // Find users who are friends and share mutual friends
  const auto mutual_friends_query = R"(
    SELECT DISTINCT u1.username as user1_name, u2.username as user2_name
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user1_id
    INNER JOIN Friendship f2 ON f1.user2_id = f2.user1_id
    INNER JOIN User u2 ON f2.user2_id = u2.user_id
    WHERE u1.user_id < u2.user_id
      AND EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user1_id = u1.user_id AND f3.user2_id = u2.user_id
      )
    GROUP BY u1.user_id, u2.user_id, u1.username, u2.username
    HAVING COUNT(f1.user2_id) > 0
  )";

  // 5. Query for users with above-average friends (nested query)
  const auto popular_users_query = R"(
    SELECT u.user_id, u.username, COUNT(f.user2_id) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user1_id
    GROUP BY u.user_id, u.username
    HAVING friend_count > (
      SELECT AVG(friend_count) 
      FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user1_id)
    )
    ORDER BY friend_count DESC
  )";

  // 6. Query for friend-of-friend relationships
  const auto fof_query = R"(
    SELECT DISTINCT u1.username as user1_name, u3.username as user2_name
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user1_id
    INNER JOIN Friendship f2 ON f1.user2_id = f2.user1_id
    INNER JOIN User u3 ON f2.user2_id = u3.user_id
    WHERE u1.user_id != u3.user_id
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f3
        WHERE f3.user1_id = u1.user_id AND f3.user2_id = u3.user_id
      )
  )";

  // 7. Execute main query and collect results
  std::vector<FriendConnection> connections;

  // Execute the mutual friends query
  auto result = conn.execute(
    Select(
      From<User>(),
      Join<Friendship>().on("User.user_id = Friendship.user1_id"),
      OrderBy("User.username")
    )
  );

  // For simplicity, return basic friend connections
  // In production, you would parse the complex query results
  for (const auto& user : users) {
    for (const auto& friendship : friendships) {
      if (friendship.user1_id == user.user_id.value) {
        // Find the friend's username
        for (const auto& friend_user : users) {
          if (friend_user.user_id.value == friendship.user2_id) {
            connections.push_back(FriendConnection{
              .user1_name = user.username,
              .user2_name = friend_user.username
            });
            break;
          }
        }
      }
    }
  }

  return connections;
}

}  // namespace analyze_social_network

