```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace calculate_order_metrics {

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  const auto conn = sqlite::connect("test_db.sqlite").value();

  // Create OrderItem table if it doesn't exist
  create_table<OrderItem>(conn | if_not_exists).value();

  // Insert all order items into the database
  for (const auto& item : items) {
    write(conn, item).value();
  }

  // Perform SELECT query with arithmetic operations to calculate metrics
  const auto metrics = select<OrderMetrics>(
    conn,
    from<OrderItem>,
    "item_id"_c,
    "order_id"_c,
    "product_id"_c,
    "unit_price"_c,
    "quantity"_c,
    coalesce("discount_rate"_c, 0.0),
    coalesce("tax_rate"_c, 0.0),
    // gross_total = unit_price * quantity
    "unit_price"_c * "quantity"_c,
    // discounted_total = unit_price * quantity * (1 - discount_rate/100)
    "unit_price"_c * "quantity"_c * (1.0 - coalesce("discount_rate"_c, 0.0) / 100.0),
    // final_total = discounted_total * (1 + tax_rate/100)
    "unit_price"_c * "quantity"_c * (1.0 - coalesce("discount_rate"_c, 0.0) / 100.0) * 
      (1.0 + coalesce("tax_rate"_c, 0.0) / 100.0),
    // unit_cost = unit_price (simplified from unit_price * quantity / quantity)
    "unit_price"_c,
    // quantity_group = quantity % 10 (modulo operation)
    "quantity"_c % 10,
    // estimated_profit = unit_price * 0.3
    "unit_price"_c * 0.3
  ).value();

  return metrics;
}

}  // namespace calculate_order_metrics
