 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Perform inner joins across tables
  // Join Order with Customer on customer_id
  // Join Order with Payment on order_id
  // Select specific columns: order_id, customer_name (from Customer.name), amount
  // Order by amount descending
