    .from<Order>()
    .inner_join<Customer>(col<&Order::customer_id> == col<&Customer::customer_id>)
    .inner_join<Payment>(col<&Order::order_id> == col<&Payment::order_id>)
    .order_by<&Consolidated::amount>(Order::DESC)
    .execute();

