#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Step 1: Create Account table and insert initial test data
  const auto initial_accounts = std::vector<Account>({
    Account{.account_id = 1, .balance = 1000.0, .status = "active"},
    Account{.account_id = 2, .balance = 2000.0, .status = "active"},
    Account{.account_id = 3, .balance = 3000.0, .status = "inactive"}
  });

  auto setup = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then(create_table<Account> | if_not_exists)
    .and_then(write(initial_accounts));

  if (!setup) {
    return false;
  }

  // Step 2: Update balances and statuses using set(...)
  // Update account 1: set both balance and status
  auto update_result = setup
    .and_then(update<Account> | 
              set("balance"_c = 1500.0, "status"_c = "premium") |
              where("account_id"_c == 1));

  if (!update_result) {
    return false;
  }

  // Update account 2: set balance and status
  update_result = update_result
    .and_then(update<Account> |
              set("balance"_c = 2500.0, "status"_c = "inactive") |
              where("account_id"_c == 2));

  if (!update_result) {
    return false;
  }

  // Update account 3: set only balance
  update_result = update_result
    .and_then(update<Account> |
              set("balance"_c = 3500.0) |
              where("account_id"_c == 3));

  if (!update_result) {
    return false;
  }

  // Step 3: Verify changes persisted
  auto accounts = update_result.and_then(read<std::vector<Account>>);

  if (!accounts) {
    return false;
  }

  // Verify the updates were applied correctly
  const auto& updated_accounts = accounts.value();

  for (const auto& account : updated_accounts) {
    if (account.account_id.value() == 1) {
      if (account.balance != 1500.0 || account.status != "premium") {
        return false;
      }
    } else if (account.account_id.value() == 2) {
      if (account.balance != 2500.0 || account.status != "inactive") {
        return false;
      }
    } else if (account.account_id.value() == 3) {
      if (account.balance != 3500.0 || account.status != "inactive") {
        return false;
      }
    }
  }

  return true;
}

}  // namespace update_set_operations
