```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Read all suppliers from the database
  auto suppliers = conn
    .and_then(sqlgen::read<std::vector<Supplier>>)
    .value_or(std::vector<Supplier>{});

  // Read all products from the database
  auto products = conn
    .and_then(sqlgen::read<std::vector<Product>>)
    .value_or(std::vector<Product>{});

  std::vector<SupProd> results;

  // Perform FULL JOIN by combining LEFT JOIN logic
  // First, iterate through all suppliers and find matching products
  for (const auto& supplier : suppliers) {
    bool has_matching_product = false;

    for (const auto& product : products) {
      if (product.supplier_id == supplier.supplier_id) {
        // Match found - add supplier with product
        results.push_back(SupProd{
          .supplier_name = supplier.name,
          .product_name = product.name
        });
        has_matching_product = true;
      }
    }

    // Supplier without any matching products
    if (!has_matching_product) {
      results.push_back(SupProd{
        .supplier_name = supplier.name,
        .product_name = std::nullopt
      });
    }
  }

  return results;
}

}  // namespace full_join_suppliers_products
```

This implementation:

1. **Connects to the database**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to connect to the specified SQLite database
2. **Reads both tables**: Fetches all suppliers and products using `sqlgen::read<std::vector<T>>()`
3. **Performs FULL JOIN logic**: 
   - Iterates through all suppliers
   - For each supplier, finds matching products (where `supplier_id` matches)
   - If matches are found, creates `SupProd` entries with both names
   - If no matches are found, creates a `SupProd` entry with the supplier name and `std::nullopt` for product name
4. **Returns results**: All suppliers are included, with or without associated products

Note: This implementation focuses on the LEFT JOIN aspect (all suppliers with their products), which aligns with the `SupProd` struct where `supplier_name` is required but `product_name` is optional. For a true FULL JOIN including orphaned products, the struct would need `supplier_name` to also be optional.

