JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  JoinAnalysis analysis;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return analysis;
  }

  // Create tables if they don't exist
  conn.and_then(create_table<Department> | if_not_exists)
      .and_then(create_table<Employee> | if_not_exists);

  // Clear existing data to ensure clean state
  conn.and_then(execute("DELETE FROM Department"));
  conn.and_then(execute("DELETE FROM Employee"));

  // Insert departments and employees
  if (!depts.empty()) {
    conn.and_then(insert(depts));
  }
  if (!emps.empty()) {
    conn.and_then(insert(emps));
  }

  // INNER JOIN: Get employees with assigned departments
  auto inner_join_query = R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    INNER JOIN Employee e ON d.department_id = e.department_id
  )";

  auto inner_result = conn.and_then(execute(inner_join_query))
                          .and_then(read<std::vector<JoinResult>>);
  if (inner_result) {
    analysis.inner_join_results = inner_result.value();
  }

  // LEFT JOIN: All employees (even without departments)
  auto left_join_query = R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id
  )";

  auto left_result = conn.and_then(execute(left_join_query))
                         .and_then(read<std::vector<JoinResult>>);
  if (left_result) {
    analysis.left_join_results = left_result.value();
  }

  // RIGHT JOIN: All departments (even without employees)
  // SQLite doesn't support RIGHT JOIN, so we use LEFT JOIN with reversed tables
  auto right_join_query = R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
  )";

  auto right_result = conn.and_then(execute(right_join_query))
                          .and_then(read<std::vector<JoinResult>>);
  if (right_result) {
    analysis.right_join_results = right_result.value();
  }

  // FULL JOIN: All employees and departments
  // SQLite doesn't support FULL OUTER JOIN, so we use UNION of LEFT JOINs
  auto full_join_query = R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON e.department_id = d.department_id
    UNION
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
    WHERE e.employee_id IS NULL
  )";

