Looking at the code fragments and the sqlgen library patterns, here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace concat_function {

struct Person {
  sqlgen::PrimaryKey<int> id;
  std::string first_name;
  std::string last_name;
};

struct FullName {
  std::string full_name;
};

/**
 * This function demonstrates CONCAT usage.
 * Returns: query value.
 */
inline auto concat_function() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create a query that selects CONCAT(first_name, ' ', last_name)
    // In SQLite, concatenation is done with the || operator
    return sqlgen::sqlite::connect()
        .and_then(create_table<Person> | if_not_exists)
        .and_then(read<std::vector<FullName>>(
            select(concat("first_name"_c, " "_s, "last_name"_c).as("full_name"_c))
                .from<Person>()
        ));
}

}  // namespace concat_function
```

The function:
1. Uses `sqlgen::sqlite::connect()` to establish a database connection
2. Creates the `Person` table if it doesn't exist using `create_table<Person> | if_not_exists`
3. Constructs a query using `concat()` to concatenate `first_name`, a space `' '`, and `last_name`
4. Maps the result to the `FullName` struct using `read<std::vector<FullName>>`
5. Returns the query result through the monadic `.and_then()` chain

