  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then([limit_count](auto conn) {
      // Join Product and Sales tables
      return sqlgen::select<TopProduct>(conn)
        .from<Product, Sales>()
        .where(
          column<Product>("product_id"_c) == column<Sales>("product_id"_c)
        )
        .select_fields(
          column<Product>("product_id"_c),
          column<Product>("product_name"_c),
          column<Product>("category"_c),
          sum(column<Product>("price"_c) * column<Sales>("quantity"_c)).as("total_sales"_c)
        )
        .group_by(
          column<Product>("product_id"_c),
          column<Product>("product_name"_c),
          column<Product>("category"_c)
        )
        .order_by(desc("total_sales"_c))
        .limit(limit_count)
        .execute();
    });

  return result.value_or(std::vector<TopProduct>{});
}

}  // namespace get_top_products
