```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;

  // Open SQLite database connection
  auto conn = sqlite::open("test_db.sqlite");

  // Raw SQL query with SQLite date/time functions
  // SQLite uses strftime for extracting date/time components
  // and julianday for calculating days between dates
  const std::string query = R"(
    SELECT 
      p.project_id, 
      p.name,
      CAST(strftime('%d', t.start_time) AS INTEGER) as day,
      CAST(strftime('%m', t.start_time) AS INTEGER) as month,
      CAST(strftime('%Y', t.start_time) AS INTEGER) as year,
      CAST(strftime('%H', t.start_time) AS INTEGER) as hour,
      CAST(strftime('%M', t.start_time) AS INTEGER) as minute,
      CAST(strftime('%S', t.start_time) AS INTEGER) as second,
      julianday(t.end_time) - julianday(t.start_time) as duration_days
    FROM Project p
    INNER JOIN TimeLog t ON p.project_id = t.project_id
  )";

  // Execute query and return results mapped to TimeMetrics struct
  return conn.query<TimeMetrics>(query);
}

}  // namespace project_time_tracking
```

This implementation:

1. **Connects to the SQLite database** using `sqlgen::sqlite::open("test_db.sqlite")`

2. **Extracts date/time components** using SQLite's `strftime` function:
   - `%d` for day
   - `%m` for month  
   - `%Y` for year
   - `%H` for hour
   - `%M` for minute
   - `%S` for second

3. **Computes days between dates** using SQLite's `julianday` function, which converts dates to Julian day numbers and subtracts them

4. **Joins the tables** using `INNER JOIN` on `project_id`

5. **Returns the results** as a vector of `TimeMetrics` structs, which the sqlgen library maps automatically from the query result columns

