```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto db = sqlgen::sqlite::open("test_db.sqlite");

  // Create table references
  auto users = db.table<User>("User");
  auto posts = db.table<Post>("Post");

  // Build query: join users with posts, group by user, compute aggregations
  auto results = users
    .left_join(posts, users.user_id == posts.user_id)
    .group_by(users.user_id, users.name)
    .select(
      users.user_id,
      users.name,
      count(posts.post_id),
      avg(length(posts.content))
    )
    .query<Stats>();

  return results;
}

}  // namespace group_by_with_aggregations
```

This implementation:
1. **Connects to the database**: Opens "test_db.sqlite" using `sqlgen::sqlite::open()`
2. **Creates table references**: Gets references to User and Post tables
3. **Performs a LEFT JOIN**: Joins User and Post tables on user_id to include all users even if they have no posts
4. **Groups by user**: Groups results by user_id and name
5. **Computes aggregations**: 
   - `count(posts.post_id)` - counts the number of posts per user
   - `avg(length(posts.content))` - calculates average content length
6. **Returns results**: Maps the query results to the Stats struct and returns as a vector

